const weekly = $('GET — Meta Insights (last 7d)').item.json.data ?? [];
const monthly = $('GET — Account lifetime stats').item.json.data?.[0] ?? {};

const totalSpend = weekly.reduce((s, c) => s + parseFloat(c.spend ?? 0), 0);
const totalImpressions = weekly.reduce((s, c) => s + parseInt(c.impressions ?? 0), 0);
const totalClicks = weekly.reduce((s, c) => s + parseInt(c.clicks ?? 0), 0);
const totalLeads = weekly.reduce((s, c) => {
  const lead = c.actions?.find(a => a.action_type === 'lead');
  return s + parseInt(lead?.value ?? 0);
}, 0);

const avgRoas = weekly.filter(c => c.purchase_roas?.[0]?.value)
  .reduce((s, c) => s + parseFloat(c.purchase_roas[0].value), 0) /
  Math.max(weekly.filter(c => c.purchase_roas?.[0]?.value).length, 1);

const sorted = [...weekly].sort((a, b) => {
  const rA = parseFloat(a.purchase_roas?.[0]?.value ?? 0);
  const rB = parseFloat(b.purchase_roas?.[0]?.value ?? 0);
  return rB - rA;
});

const now = new Date();
const weekStr = `${now.getFullYear()}-W${String(Math.ceil(now.getDate() / 7)).padStart(2, '0')}`;

return [{ json: {
  period: weekStr,
  weekly: { campaigns: weekly, totalSpend: totalSpend.toFixed(2), totalImpressions, totalClicks, totalLeads, avgRoas: avgRoas.toFixed(2), avgCtr: totalImpressions > 0 ? ((totalClicks / totalImpressions) * 100).toFixed(2) : '0', avgCpm: totalImpressions > 0 ? ((totalSpend / totalImpressions) * 1000).toFixed(2) : '0' },
  monthly: { spend: monthly.spend ?? 0, impressions: monthly.impressions ?? 0 },
  topCampaign: sorted[0]?.campaign_name ?? 'N/A',
  worstCampaign: sorted[sorted.length - 1]?.campaign_name ?? 'N/A',
  campaignCount: weekly.length,
}}];

